import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import Footer from './Footer';
import Navbar from './Navbar';
import { addToCart } from './cartUtils';
import AddedToCartOverlay from './AddedToCartOverlay';
import ProductDetailsOverlay from './ProductDetailsOverlay';

export default function Products1() {
  const navigate = useNavigate();
  const [activeCategory, setActiveCategory] = useState("All");
  const [searchTerm, setSearchTerm] = useState("");

  const categories = ["All", "Cement", "Nails", "Paint", "Plumbing", "Electrical", "Tools"];

  const featuredProducts = [
    { id: 'f1', title: "Cement", brand: "Holcim Cement", price: "P 350", img: "https://5.imimg.com/data5/SELLER/Default/2022/6/TZ/YT/LI/121020182/holcim-premium-cement-1000x1000.jpg" },
    { id: 'f2', title: "Impact Driver", brand: "Milwaukee", price: "P 350", img: "https://static.summitracing.com/global/images/prod/xlarge/mwt-2967-20_xl.jpg" },
    { id: 'f3', title: "Adjustable Wrench", brand: "Milwaukee", price: "P 350", img: "https://images.plumbersstock.com/default/500/500/large/581052.webp" }
  ];

  const regularProducts = [
    { id: 1, title: "Tape Measure", brand: "Stanley", price: "P 125", img: "https://i5.walmartimages.com/asr/bc5115aa-6aef-4ef1-b8f4-2892d16b0224_1.703ae051dc43ce85d21ec8934712690a.jpeg" },
    { id: 2, title: "Cordless Drill", brand: "DeWalt", price: "P 4,850", img: "data:image/jpeg;base64," },
    { id: 3, title: "Handsaw", brand: "Stanley", price: "P 450", img: "data:image/jpeg;base64," },
    { id: 4, title: "20pcs Drill Bit Set", brand: "DeWalt", price: "P 1,250", img: "data:image/jpeg;base64," },
    { id: 5, title: "Shovel", brand: "Stanley", price: "P 850", img: "data:image/jpeg;base64," },
    { id: 6, title: "Screwdrivers Set", brand: "Milwaukee", price: "P 1,150", img: "data:image/jpeg;base64," },
    { id: 7, title: "Pipe Set", brand: "Tough", price: "P 650", img: "data:image/jpeg;base64," },
    { id: 8, title: "Coping Saw", brand: "Stanley", price: "P 320", img: "data:image/png;base64," },
    { id: 9, title: "Paint Brush", brand: "Stanley", price: "P 120", img: "data:image/jpeg;base64," },
    { id: 10, title: "Wood Chisel", brand: "Stanley", price: "P 380", img: "data:image/jpeg;base64," },
    { id: 11, title: "Rubber Mallet", brand: "Stanley", price: "P 250", img: "data:image/jpeg;base64," },
    { id: 12, title: "3 in. Screwdriver", brand: "Stanley", price: "P 110", img: "data:image/png;base64," },
    { id: 13, title: "Hacksaw Blade", brand: "Stanley", price: "P 45", img: "data:image/jpeg;base64," },
    { id: 14, title: "Paint Thinner", brand: "BOYSEN", price: "P 180", img: "data:image/jpeg;base64," },
    { id: 15, title: "Spray Paint Black", brand: "Bosny", price: "P 165", img: "data:image/jpeg;base64," },
    { id: 16, title: "Masking Tape", brand: "Armak", price: "P 45", img: "data:image/jpeg;base64," },
    { id: 17, title: "Scrapper", brand: "Stanley", price: "P 85", img: "data:image/jpeg;base64," },
    { id: 18, title: "Paint", brand: "Davies", price: "P 450", img: "data:image/jpeg;base64," },
    { id: 19, title: "Welder's Chalk", brand: "Bestweld", price: "P 25", img: "data:image/jpeg;base64," },
    { id: 20, title: "Paint Roller", brand: "Mr. Tool", price: "P 145", img: "data:image/jpeg;base64," },
    { id: 21, title: "Polituff", brand: "Polituff", price: "P 220", img: "https://encrypted-tbn0.gstatic.com/shopping?q=tbn:ANd9GcSPmVkuM4eJl_RX2UoJEl2Ppv210HhFF8hLfOuNGW_uyOgor0YYa1fTl-xXWk7wmvKpChi4R8Fd6M8knxgqKVDnXRBt3bNmt_WEQ3rm8ilDLs40pzsxvNPm9pZsOwWnOY2tTYm91Q&usqp=CAc" },
    { id: 22, title: "Semi-gloss Paint", brand: "BOYSEN", price: "P 580", img: "data:image/jpeg;base64," },
    { id: 23, title: "Quick Dry Paint", brand: "BOYSEN", price: "P 550", img: "data:image/jpeg;base64," },
    { id: 24, title: "Quick Dry Paint", brand: "BOYSEN", price: "P 550", img: "data:image/jpeg;base64," },
    { id: 25, title: "Plastic Paint Roller", brand: "Pioneer", price: "P 85", img: "data:image/jpeg;base64," },
    { id: 26, title: "Aerosol Spray", brand: "WD-40", price: "P 280", img: "data:image/jpeg;base64," },
    { id: 27, title: "Sandpaper", brand: "Norton", price: "P 15", img: "data:image/jpeg;base64," },
    { id: 28, title: "Paint", brand: "BOYSEN", price: "P 450", img: "data:image/jpeg;base64," },
  ];

  // Filtering Logic
  const filteredFeatured = featuredProducts.filter(p =>
    p.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    p.brand.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const filteredRegular = regularProducts.filter(p =>
    p.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    p.brand.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // Pagination Logic for Regular Products
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 12; // Display 12 items per page

  const indexOfLastItem = currentPage * itemsPerPage;
  const indexOfFirstItem = indexOfLastItem - itemsPerPage;
  const currentRegularItems = filteredRegular.slice(indexOfFirstItem, indexOfLastItem);
  const totalPages = Math.ceil(filteredRegular.length / itemsPerPage);

  const paginate = (pageNumber) => setCurrentPage(pageNumber);
  const nextPage = () => setCurrentPage(prev => (prev < totalPages ? prev + 1 : prev));

  const [showAddedOverlay, setShowAddedOverlay] = useState(false);
  const [addedProductName, setAddedProductName] = useState("");

  const triggerOverlay = (name) => {
    setAddedProductName(name);
    setShowAddedOverlay(true);
    setTimeout(() => setShowAddedOverlay(false), 2000);
  };

  const [selectedProduct, setSelectedProduct] = useState(null);
  const [isDetailsOpen, setIsDetailsOpen] = useState(false);

  const handleProductClick = (product) => {
    setSelectedProduct(product);
    setIsDetailsOpen(true);
  };

  const handleAddToCart = (product) => {
    const success = addToCart(product);
    if (success) {
      triggerOverlay(product.title);
    } else {
      navigate('/login');
    }
  };

  return (
    <div className="min-h-screen font-body flex flex-col">
      <Navbar />

      {/* Main Content */}
      <div
        className="flex-1 w-full relative"
        style={{
          backgroundColor: '#dbdbdb',
          backgroundImage: "url('/bg.jpg')",
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          backgroundRepeat: 'no-repeat',
          backgroundAttachment: 'fixed'
        }}
      >
        <div className="max-w-[1300px] mx-auto px-4 md:px-10 pt-8 md:pt-10 pb-16 flex flex-col items-center relative z-10">

          {/* Header Row */}
          <div className="flex flex-col md:flex-row justify-between items-center w-full mb-6 gap-4 md:gap-6">
            <h1 className="text-[24px] md:text-[32px] text-[#2c2c2c] font-normal tracking-tight">Our Products</h1>
            <div className="relative w-full md:w-auto">
              <div className="flex items-center bg-white rounded-md px-4 py-2 w-full md:w-[400px] shadow-sm border border-gray-200">
                <svg className="w-4 h-4 text-gray-400 mr-3" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
                <input
                  type="text"
                  placeholder="Search products..."
                  className="w-full bg-transparent focus:outline-none text-[14px] text-gray-700 placeholder-gray-400 font-medium"
                  value={searchTerm}
                  onChange={(e) => {
                    setSearchTerm(e.target.value);
                    setCurrentPage(1); // Reset to first page on search
                  }}
                />
              </div>
            </div>
          </div>

          {/* Categories Filter Bar */}
          <div className="w-full bg-[#ccddc2] rounded-xl py-3 px-4 flex gap-3 md:gap-4 md:justify-center mb-8 md:mb-10 shadow-sm border border-[#b8cfa9]/40 overflow-x-auto" style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}>
            {categories.map((cat) => (
              <button
                key={cat}
                onClick={() => {
                  if (cat === "Cement") navigate('/products/cement');
                  else if (cat === "Nails") navigate('/products/nails');
                  else if (cat === "Paint") navigate('/products/paint');
                  else if (cat === "Plumbing") navigate('/products/plumbing');
                  else if (cat === "Electrical") navigate('/products/electrical');
                  else if (cat === "Tools") navigate('/products/tools');
                  else setActiveCategory(cat);
                }}
                className={`px-4 md:px-6 py-2 rounded-lg font-medium text-[13px] md:text-[14px] transition-all duration-300 shadow-sm whitespace-nowrap shrink-0 ${activeCategory === cat ? 'bg-[#5ea73c] text-white shadow-md' : 'bg-white text-gray-800 hover:bg-gray-50'}`}
              >
                {cat}
              </button>
            ))}
          </div>

          <div className="w-full flex flex-col items-center gap-6">

            {/* Featured Row */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 w-full">
              {filteredFeatured.length > 0 ? filteredFeatured.map((p) => (
                <div
                  key={p.id}
                  onClick={() => handleProductClick(p)}
                  className="relative bg-[#d6d6d6] rounded-[16px] p-4 md:p-6 pb-6 flex flex-col shadow-md border border-white/40 transition-transform transform hover:-translate-y-1 w-full cursor-pointer group"
                >
                  <div className="flex-1 flex items-center justify-center mb-4 overflow-hidden px-4">
                    <img src={p.img} alt={p.title} className="w-full h-[180px] md:h-[240px] object-contain mix-blend-multiply transition-transform group-hover:scale-110" />
                  </div>
                  <div className="px-1 shrink-0 text-left">
                    <h3 className="text-[20px] md:text-[24px] font-normal text-gray-900 leading-tight mb-0.5">{p.title}</h3>
                    <p className="text-[13px] md:text-[14px] font-medium text-gray-600 mb-2">{p.brand}</p>
                    <p className="text-[26px] md:text-[32px] font-black text-black leading-none mb-4 md:mb-6">{p.price}</p>
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        handleAddToCart(p);
                      }}
                      className="w-full py-3 bg-[#1e4b2a] text-white font-bold text-[14px] rounded hover:bg-[#15341d] transition-colors tracking-wide"
                    >
                      ADD TO CART
                    </button>
                  </div>
                </div>
              )) : null}
            </div>

            {/* Regular Grid */}
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3 md:gap-x-6 md:gap-y-8 justify-items-center w-full mt-4 min-h-[400px]">
              {currentRegularItems.length > 0 ? (
                currentRegularItems.map((p) => (
                  <div
                    key={p.id}
                    onClick={() => handleProductClick(p)}
                    className="relative bg-[#d6d6d6] rounded-[12px] md:rounded-[16px] p-3 md:p-5 flex flex-col shadow-md border border-white/40 transition-transform transform hover:-translate-y-1 w-full cursor-pointer group"
                  >
                    <div className="flex-1 w-full flex items-center justify-center mb-3 md:mb-4 overflow-hidden min-h-[100px] md:min-h-[160px]">
                      <img src={p.img || `https://placehold.co/300x300/d6d6d6/888888?text=${encodeURIComponent(p.title)}`} alt={p.title} className="max-w-full max-h-full object-contain mix-blend-multiply transition-transform group-hover:scale-110" />
                    </div>

                    <div className="px-0.5 md:px-1 shrink-0 text-left flex flex-col justify-end">
                      <h3 className="text-[13px] md:text-[17px] font-bold text-gray-900 leading-tight mb-0.5 md:mb-1 whitespace-nowrap overflow-hidden text-ellipsis font-serif">{p.title}</h3>
                      <p className="text-[10px] md:text-[11px] font-medium text-gray-500 mb-2 md:mb-3">{p.brand}</p>
                      <div className="flex items-center justify-between">
                        <span className="text-[18px] md:text-[24px] font-black text-black leading-none">{p.price}</span>
                        <button
                          onClick={(e) => {
                            e.stopPropagation();
                            handleAddToCart(p);
                          }}
                          className="w-7 h-7 md:w-8 md:h-8 rounded-full border-[1.5px] border-[#377b42] flex items-center justify-center text-[#377b42] hover:bg-[#377b42] hover:text-white transition-all duration-300 bg-transparent shrink-0"
                        >
                          <svg className="w-3.5 h-3.5 md:w-4 md:h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M12 6v6m0 0v6m0-6h6m-6 0H6"></path></svg>
                        </button>
                      </div>
                    </div>
                  </div>
                ))
              ) : (
                <div className="col-span-full py-20 text-center">
                  <p className="text-gray-500 font-bold text-lg">No products found matching "{searchTerm}"</p>
                </div>
              )}
            </div>

            {/* Pagination Controls */}
            {totalPages > 1 && (
              <div className="flex justify-center items-center gap-2 mt-8 pb-4">
                {Array.from({ length: totalPages }, (_, i) => i + 1).map(num => (
                  <button
                    key={num}
                    onClick={() => paginate(num)}
                    className={`w-8 h-8 rounded shadow-sm text-[13px] font-bold transition-colors ${currentPage === num ? 'bg-[#5ea73c] text-white' : 'bg-white text-gray-700 hover:bg-gray-100'}`}
                  >
                    {num}
                  </button>
                ))}
                <button
                  onClick={nextPage}
                  disabled={currentPage === totalPages}
                  className={`px-4 h-8 rounded shadow-sm text-[13px] font-medium transition-colors flex items-center gap-1 ml-1 ${currentPage === totalPages ? 'bg-gray-200 text-gray-400 cursor-not-allowed' : 'bg-white text-gray-700 hover:bg-gray-100'}`}
                >
                  Next page <span className="font-serif">»</span>
                </button>
              </div>
            )}

          </div>
        </div>

        <AddedToCartOverlay isVisible={showAddedOverlay} productName={addedProductName} />

        <ProductDetailsOverlay
          product={selectedProduct}
          isOpen={isDetailsOpen}
          onClose={() => setIsDetailsOpen(false)}
          onAddToCart={handleAddToCart}
        />
      </div>

      <Footer />
    </div>
  );
}
